solutions.javascript:
// Solution
function twoSum(nums, target) {
  let hashTable = {}
  for (let i = 0; i < nums.length; i++) {
    if (!hashTable[target - nums[i]]) {
      hashTable[nums[i]] = i
    } else {
      return [hashTable[target - nums[i]], i]
    }
  }
  return []
}
